Here's a complete implementation:

**XAML ‚Äî wrap CollectionView in RefreshView for pull-to-refresh:**

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             xmlns:models="clr-namespace:MyApp.Models"
             xmlns:vm="clr-namespace:MyApp.ViewModels"
             x:Class="MyApp.Views.ItemsPage"
             x:DataType="vm:ItemsViewModel">

    <RefreshView IsRefreshing="{Binding IsRefreshing}"
                 Command="{Binding RefreshCommand}">
        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                        SelectionChangedCommand="{Binding ItemSelectedCommand}">
            <CollectionView.ItemTemplate>
                <DataTemplate x:DataType="models:Item">
                    <Grid Padding="12" ColumnDefinitions="Auto,*">
                        <Image Source="{Binding Icon}"
                               WidthRequest="48" HeightRequest="48" />
                        <VerticalStackLayout Grid.Column="1" VerticalOptions="Center" Padding="8,0">
                            <Label Text="{Binding Name}" FontAttributes="Bold" />
                            <Label Text="{Binding Description}" FontSize="12" TextColor="Gray" />
                        </VerticalStackLayout>
                    </Grid>
                </DataTemplate>
            </CollectionView.ItemTemplate>
            <CollectionView.EmptyView>
                <ContentView>
                    <Label Text="No items found."
                           HorizontalOptions="Center" VerticalOptions="Center" />
                </ContentView>
            </CollectionView.EmptyView>
        </CollectionView>
    </RefreshView>
</ContentPage>
```

**ViewModel ‚Äî using CommunityToolkit.Mvvm:**

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private Item? currentItem;

    [ObservableProperty]
    private bool isRefreshing;

    public ObservableCollection<Item> Items { get; } = new();

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (CurrentItem is null) return;

        // Navigate, then clear selection so user can re-select the same item
        await Shell.Current.GoToAsync($"detail?id={CurrentItem.Id}");
        CurrentItem = null;
    }

    [RelayCommand]
    private async Task Refresh()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            MainThread.BeginInvokeOnMainThread(() =>
            {
                Items.Clear();
                foreach (var item in data)
                    Items.Add(item);
            });
        }
        finally
        {
            IsRefreshing = false;   // stops the refresh spinner
        }
    }
}
```

**Key binding points:**

| XAML Property | ViewModel Property | Notes |
|---|---|---|
| `RefreshView.IsRefreshing` | `IsRefreshing` (bool) | Set `false` when done to stop spinner |
| `RefreshView.Command` | `RefreshCommand` | Calls your API, repopulates `Items` |
| `SelectedItem` | `CurrentItem` (TwoWay) | Holds the tapped item |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires on tap ‚Üí navigates, then nulls `CurrentItem` |
| `ItemsSource` | `Items` (ObservableCollection) | Must be `ObservableCollection<T>`, not `List<T>` |

**Important details:**
- Set `CurrentItem = null` after navigation so the same item can be re-selected later.
- Always set `IsRefreshing = false` in a `finally` block so the spinner stops even on errors.
- Use `x:DataType` on both the page and the `DataTemplate` for compiled bindings.
- Update collections on the **UI thread** via `MainThread.BeginInvokeOnMainThread`.
